import React from 'react';

interface Props {
  label: string;
  value: number;
  description: string;
  trend: string;
  variant: 'primary' | 'danger' | 'warning' | 'caution';
}

const RiskIndexCard: React.FC<Props> = ({ label, value, description, trend, variant }) => {
  const getColors = () => {
    switch(variant) {
      case 'danger': return 'from-rose-500 to-red-600 shadow-rose-900/20 text-rose-400';
      case 'warning': return 'from-amber-500 to-orange-600 shadow-amber-900/20 text-amber-400';
      case 'caution': return 'from-emerald-500 to-teal-600 shadow-emerald-900/20 text-emerald-400';
      default: return 'from-indigo-500 to-blue-600 shadow-indigo-900/20 text-indigo-400';
    }
  };

  return (
    <div className="bg-slate-900/40 rounded-2xl border border-slate-800 p-5 group hover:border-slate-700 transition-all flex flex-col">
      <div className="flex justify-between items-start mb-4">
        <span className="text-xs font-bold uppercase tracking-widest text-slate-500">{label}</span>
        <span className={`text-[10px] px-1.5 py-0.5 rounded border ${trend.startsWith('+') ? 'text-emerald-400 border-emerald-500/20 bg-emerald-500/10' : 'text-rose-400 border-rose-500/20 bg-rose-500/10'}`}>
          {trend}
        </span>
      </div>

      <div className="flex items-end gap-2 mb-4">
        <span className="text-4xl font-bold tracking-tighter mono">
          {Math.round(value)}
        </span>
        <span className="text-sm text-slate-500 mb-1 font-mono">/100</span>
      </div>

      <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden mb-4">
        <div 
          className={`h-full bg-gradient-to-r ${getColors()} transition-all duration-1000`} 
          style={{ width: `${value}%` }}
        />
      </div>

      <p className="text-xs text-slate-500 leading-relaxed italic">
        {description}
      </p>
    </div>
  );
};

export default RiskIndexCard;

import React from 'react';

const CognitiveHeatmap: React.FC = () => {
  // Simple abstract representation of a map
  const regions = [
    { x: 20, y: 20, r: 30, color: '#f43f5e', label: 'North' },
    { x: 70, y: 30, r: 20, color: '#fbbf24', label: 'East' },
    { x: 40, y: 60, r: 40, color: '#6366f1', label: 'Central' },
    { x: 15, y: 80, r: 25, color: '#2dd4bf', label: 'West' },
    { x: 80, y: 75, r: 15, color: '#6366f1', label: 'South' },
  ];

  return (
    <svg viewBox="0 0 100 100" className="w-full h-full opacity-80">
      <defs>
        {regions.map((r, i) => (
          <radialGradient key={`grad-${i}`} id={`grad-${i}`}>
            <stop offset="0%" stopColor={r.color} stopOpacity="0.6" />
            <stop offset="100%" stopColor={r.color} stopOpacity="0" />
          </radialGradient>
        ))}
      </defs>

      {/* Abstract Map Contours */}
      <path 
        d="M10,20 Q30,5 50,15 T90,20 Q95,40 85,60 T70,90 Q40,95 20,85 T5,50 Z" 
        fill="none" 
        stroke="#1e293b" 
        strokeWidth="0.5" 
      />

      {/* Heat Points */}
      {regions.map((r, i) => (
        <circle 
          key={i} 
          cx={r.x} 
          cy={r.y} 
          r={r.r} 
          fill={`url(#grad-${i})`} 
          className="animate-pulse"
          style={{ animationDuration: `${2 + i}s` }}
        />
      ))}

      {/* Region Markers */}
      {regions.map((r, i) => (
        <g key={`marker-${i}`}>
          <circle cx={r.x} cy={r.y} r="1" fill="#fff" />
          <text x={r.x + 2} y={r.y - 2} fill="#94a3b8" fontSize="2.5" fontWeight="bold">
            {r.label}
          </text>
        </g>
      ))}
    </svg>
  );
};

export default CognitiveHeatmap;

import React, { useState } from 'react';
import { Play, RotateCcw, Save, MessageSquare, Terminal, ChevronRight } from 'lucide-react';
import { GoogleGenAI } from '@google/genai';

const SimulationView: React.FC = () => {
  const [scenario, setScenario] = useState('Policy Shift: National Energy Subsidy Removal');
  const [isSimulating, setIsSimulating] = useState(false);
  const [simulationResult, setSimulationResult] = useState<string | null>(null);

  const runSimulation = async () => {
    setIsSimulating(true);
    setSimulationResult(null);

    // Simulate thinking delay then call Gemini for a "Brief"
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analyze the following scenario using psychographic intelligence and predict population response:
        Scenario: ${scenario}
        Format: Return a JSON-like analysis with "Likely Outcome", "Risk Vectors", and "Counter-Narrative Strategy".`,
        config: {
          thinkingConfig: { thinkingBudget: 0 }
        }
      });
      setSimulationResult(response.text || "Failed to generate simulation. Data stream interrupted.");
    } catch (e) {
      setSimulationResult("ERROR: Sovereign simulation layer unreachable. Ensure inter-agency handshake is valid.");
    } finally {
      setIsSimulating(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
      <div className="space-y-6">
        <div className="bg-slate-900/40 rounded-2xl border border-slate-800 p-6">
          <h3 className="text-lg font-bold mb-4">Simulation Parameterization</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Scenario Definition</label>
              <textarea 
                value={scenario}
                onChange={(e) => setScenario(e.target.value)}
                className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-sm focus:outline-none focus:border-indigo-500/50 min-h-[120px]"
                placeholder="Describe the policy change or narrative event..."
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Confidence Threshold</label>
                <select className="w-full bg-slate-950 border border-slate-800 rounded-lg px-3 py-2 text-sm focus:outline-none">
                  <option>95% (High Fidelity)</option>
                  <option>80% (Rapid Iteration)</option>
                  <option>65% (Exploratory)</option>
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2 tracking-widest">Time Horizon</label>
                <select className="w-full bg-slate-950 border border-slate-800 rounded-lg px-3 py-2 text-sm focus:outline-none">
                  <option>T+24 Hours</option>
                  <option>T+7 Days</option>
                  <option>T+30 Days</option>
                </select>
              </div>
            </div>

            <div className="flex gap-2 pt-2">
              <button 
                onClick={runSimulation}
                disabled={isSimulating}
                className="flex-1 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-lg shadow-indigo-900/20"
              >
                {isSimulating ? <RotateCcw size={18} className="animate-spin" /> : <Play size={18} />}
                {isSimulating ? 'Processing Models...' : 'Run Prediction Engine'}
              </button>
            </div>
          </div>
        </div>

        <div className="bg-slate-900/40 rounded-2xl border border-slate-800 p-6">
          <h3 className="text-sm font-bold uppercase text-slate-500 mb-4 tracking-wider">Simulation Capabilities</h3>
          <div className="grid grid-cols-2 gap-3">
            {[
              { label: 'Policy Impact', desc: 'Forecast public response' },
              { label: 'Narrative Stress', desc: 'Message framing analysis' },
              { label: 'Crisis Modeling', desc: 'Pre-incident preparedness' },
              { label: 'Counter-Narrative', desc: 'Mitigation effectiveness' }
            ].map((cap, i) => (
              <div key={i} className="bg-slate-950/50 p-3 rounded-xl border border-slate-800 hover:border-slate-700 cursor-help group transition-all">
                <p className="text-sm font-bold group-hover:text-indigo-400 transition-colors">{cap.label}</p>
                <p className="text-[10px] text-slate-500 mt-1">{cap.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="bg-slate-950 border border-slate-800 rounded-2xl flex flex-col overflow-hidden relative min-h-[500px]">
        {/* Terminal Header */}
        <div className="h-10 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-4">
          <div className="flex items-center gap-2">
            <Terminal size={14} className="text-emerald-500" />
            <span className="text-[10px] font-mono font-bold text-slate-400 tracking-wider">PREDICTIVE_GOVERNANCE_OUTPUT.LOG</span>
          </div>
          <div className="flex gap-1.5">
            <div className="w-2 h-2 rounded-full bg-slate-700"></div>
            <div className="w-2 h-2 rounded-full bg-slate-700"></div>
            <div className="w-2 h-2 rounded-full bg-slate-700"></div>
          </div>
        </div>

        <div className="flex-1 p-6 font-mono text-[13px] overflow-y-auto leading-relaxed text-slate-300">
          {isSimulating ? (
            <div className="space-y-4">
              <p className="animate-pulse text-indigo-400">Initializing Monte Carlo Psychographic Sampling...</p>
              <p className="animate-pulse delay-100 text-slate-500">Injecting OSINT Sentiment Deltas [4.2s latency]...</p>
              <p className="animate-pulse delay-300 text-slate-500">Cross-referencing Cognitive Style biases (Analytical vs Intuitive)...</p>
              <p className="animate-pulse delay-500 text-slate-500">Normalizing output probability vectors...</p>
            </div>
          ) : simulationResult ? (
            <div className="whitespace-pre-wrap">
              {simulationResult}
              <div className="mt-8 pt-4 border-t border-slate-800 text-[11px] text-slate-500 italic">
                -- Simulation complete. Audit log preserved. Human-in-the-loop verification required before operationalization. --
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-center opacity-30 select-none">
              <MessageSquare size={48} className="mb-4 text-indigo-500" />
              <p>Ready for operational simulation.</p>
              <p className="text-[10px] mt-2">Enter parameters and initiate engine.</p>
            </div>
          )}
        </div>

        {simulationResult && !isSimulating && (
          <div className="p-4 bg-slate-900 border-t border-slate-800 flex gap-2">
            <button className="flex-1 bg-slate-800 hover:bg-slate-700 text-white text-xs py-2 rounded-lg font-bold flex items-center justify-center gap-2">
              <Save size={14} /> Save to Scenario Playbook
            </button>
            <button className="flex-1 bg-indigo-600/20 hover:bg-indigo-600/30 text-indigo-400 text-xs py-2 rounded-lg font-bold flex items-center justify-center gap-2 border border-indigo-500/30">
              Generate Executive Brief <ChevronRight size={14} />
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default SimulationView;

